#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <omp.h>

#ifdef TIMING
#include "timing.h"

struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#define BLOCK_SIZE 256
#define STR_SIZE 256
#define HALO 1 

void run(int argc, char** argv);

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9
int pyramid_height;

void
init(int argc, char** argv)
{
	if(argc==4){
		cols = atoi(argv[1]);
		rows = atoi(argv[2]);
                pyramid_height=atoi(argv[3]);
	}else{
                printf("Usage: dynproc row_len col_len pyramid_height\n");
                exit(0);
        }
	data = new int[rows*cols];
	wall = new int*[rows];
	for(int n=0; n<rows; n++)
		wall[n]=data+cols*n;
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

// OpenMP equivalent of dynproc_kernel
void dynproc_kernel_cpu(
                int iteration, 
                int *wall,
                int *src,
                int *results,
                int cols, 
                int rows,
                int startStep,
                int border,
                int blockIdx)
{
    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
    int blkX = small_block_cols * blockIdx - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int prev[BLOCK_SIZE];
    int result_arr[BLOCK_SIZE];

    // validXmin and validXmax define the valid range of threads inside block
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    // Initialize prev array from src for valid xidx
    #pragma omp parallel for
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        int xidx = blkX + tx;
        if (IN_RANGE(xidx, 0, cols - 1))
            prev[tx] = src[xidx];
        else
            prev[tx] = 0;
    }

    bool computed = false;

    for (int i = 0; i < iteration; i++) {
        #pragma omp parallel for
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            int W = tx - 1;
            int E = tx + 1;
            if (W < validXmin) W = validXmin;
            if (E > validXmax) E = validXmax;

            bool isValid = IN_RANGE(tx, validXmin, validXmax);
            if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                int left = prev[W];
                int up = prev[tx];
                int right = prev[E];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);
                int index = cols * (startStep + i) + xidx;
                result_arr[tx] = shortest + wall[index];
            } else {
                result_arr[tx] = 0; // safe default
            }
        }
        // synchronize equivalent
        #pragma omp barrier

        if (i == iteration - 1)
            break;

        #pragma omp parallel for
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2)) {
                prev[tx] = result_arr[tx];
            }
        }
        #pragma omp barrier
    }

    // Write back results for valid indices
    #pragma omp parallel for
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        int xidx = blkX + tx;
        bool isValid = IN_RANGE(tx, validXmin, validXmax);
        if (isValid && IN_RANGE(xidx, 0, cols - 1)) {
            results[xidx] = result_arr[tx];
        }
    }
}

int calc_path(int *wall, int *result[2], int rows, int cols,
              int pyramid_height, int blockCols, int borderCols)
{
    int src = 1, dst = 0;

    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;

        int iteration = (pyramid_height < rows - t - 1) ? pyramid_height : (rows - t - 1);

        #pragma omp parallel for
        for (int bx = 0; bx < blockCols; bx++) {
            dynproc_kernel_cpu(
                iteration,
                wall,
                result[src],
                result[dst],
                cols,
                rows,
                t,
                borderCols,
                bx);
        }
    }
    return dst;
}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height)*HALO;
    int smallBlockCol = BLOCK_SIZE-(pyramid_height)*HALO*2;
    int blockCols = cols/smallBlockCol+((cols%smallBlockCol==0)?0:1);

    printf("pyramidHeight: %d\ngridSize: [%d]\nborder:[%d]\nblockSize: %d\nblockGrid:[%d]\ntargetBlock:[%d]\n",\
	pyramid_height, cols, borderCols, BLOCK_SIZE, blockCols, smallBlockCol);

    int size = rows*cols;

    int* cpuWall = data + cols; // wall data excluding first row
    int* cpuResult[2];
    cpuResult[0] = new int[cols];
    cpuResult[1] = new int[cols];

    // Initialize cpuResult[0] with first row of data
    for (int i = 0; i < cols; i++) {
        cpuResult[0][i] = data[i];
    }

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(cpuWall, cpuResult, rows, cols,
                             pyramid_height, blockCols, borderCols);

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy result from cpuResult[final_ret] to result array
    for (int i = 0; i < cols; i++) {
        result[i] = cpuResult[final_ret][i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
            printf("%d ",data[i]) ;
    printf("\n") ;
    for (int i = 0; i < cols; i++)
            printf("%d ",result[i]) ;
    printf("\n") ;
#endif

    delete [] cpuResult[0];
    delete [] cpuResult[1];

    delete [] data;
    delete [] wall;
    delete [] result;

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}
